import React, { useState, useEffect } from 'react';
import api from './api';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import TransactionList from './components/TransactionList';

function App() {
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [user, setUser] = useState(null);
  const [view, setView] = useState('dashboard');
  const [authView, setAuthView] = useState('login');
  const [transactions, setTransactions] = useState([]);
  const [budgets, setBudgets] = useState([]);
  const [investments, setInvestments] = useState([]);

  const login = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/login', { 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      setToken(res.data.token);
      localStorage.setItem('token', res.data.token);
      setUser(res.data.user);
      setView('dashboard');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const register = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/register', { 
        name: e.target.name.value, 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      alert('Registered successfully! Please login.');
      setAuthView('login');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem('token');
    setView('dashboard');
  };

  const loadTransactions = async () => {
    try {
      const res = await api.get('/transactions');
      setTransactions(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadBudgets = async () => {
    try {
      const res = await api.get('/budgets');
      setBudgets(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadInvestments = async () => {
    try {
      const res = await api.get('/investments');
      setInvestments(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const refreshAll = async () => {
    await loadTransactions();
    await loadBudgets();
    await loadInvestments();
  };

  const addTransaction = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData(e.target);
      const data = Object.fromEntries(formData);
      await api.post('/transactions', data);
      e.target.reset();
      refreshAll();
    } catch (err) {
      alert(err.response?.data?.error || 'Add failed');
    }
  };

  const addBudget = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData(e.target);
      const data = Object.fromEntries(formData);
      await api.post('/budgets', { month: data.month, limit: parseFloat(data.limit) });
      e.target.reset();
      refreshAll();
    } catch (err) {
      alert(err.response?.data?.error || 'Set budget failed');
    }
  };

  const addInvestment = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData(e.target);
      const data = Object.fromEntries(formData);
      await api.post('/investments', { 
        principal: parseFloat(data.principal), 
        rate: parseFloat(data.rate), 
        duration: parseInt(data.duration) 
      });
      e.target.reset();
      refreshAll();
    } catch (err) {
      alert(err.response?.data?.error || 'Add investment failed');
    }
  };

  useEffect(() => {
    if (token) {
      refreshAll();
    }
  }, [token]);

  if (!token) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-purple-900 to-pink-800 flex items-center justify-center p-4 relative overflow-hidden">
        <div className="bg-white/95 backdrop-blur-xl rounded-3xl shadow-2xl p-12 max-w-md w-full border border-white/30 relative z-10">
          <div className="text-center mb-12">
            <div className="inline-flex items-center px-6 py-3 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl shadow-lg mb-6 mx-auto">
              <svg className="w-8 h-8 text-white mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className="text-xl font-bold text-white">FinTrack</span>
            </div>
            <h1 className="text-4xl font-black bg-gradient-to-r from-gray-800 to-gray-700 bg-clip-text text-transparent mb-3">FinTrack</h1>
            <p className="text-gray-600 text-xl font-medium">Your Personal Finance Dashboard</p>
          </div>

          {authView === 'login' ? (
            <form onSubmit={login} className="space-y-6">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Email</label>
                <input name="email" type="email" required className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/30 focus:border-indigo-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Password</label>
                <input name="password" type="password" required className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/30 focus:border-indigo-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" />
              </div>
              <button type="submit" className="w-full bg-gradient-to-r from-indigo-600 via-purple-600 to-pink-600 text-white py-6 px-8 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-indigo-700 hover:via-purple-700 hover:to-pink-700 transform hover:scale-[1.02] hover:-translate-y-1 transition-all duration-300">
                Sign In
              </button>
            </form>
          ) : (
            <form onSubmit={register} className="space-y-6">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Full Name</label>
                <input name="name" type="text" required className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Email</label>
                <input name="email" type="email" required className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Password</label>
                <input name="password" type="password" minLength="6" required className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" />
              </div>
              <button type="submit" className="w-full bg-gradient-to-r from-emerald-500 to-teal-600 text-white py-6 px-8 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-emerald-600 hover:to-teal-700 transform hover:scale-[1.02] hover:-translate-y-1 transition-all duration-300">
                Create Free Account
              </button>
            </form>
          )}

          <div className="mt-10 pt-10 border-t-2 border-indigo-100 text-center">
            <button 
              type="button"
              onClick={() => setAuthView(authView === 'login' ? 'register' : 'login')}
              className="text-indigo-600 hover:text-indigo-700 font-bold text-lg"
            >
              {authView === 'login' ? 'Create Account' : 'Back to Login'}
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 via-blue-50 to-indigo-100">
      <nav className="bg-white shadow-lg border-b border-gray-200/50 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-6 py-5 flex justify-between items-center">
          <div className="flex items-center space-x-4">
            <h1 className="text-3xl font-black bg-gradient-to-r from-indigo-600 to-purple-600 bg-clip-text text-transparent">
              FinTrack
            </h1>
            <span className="text-sm text-gray-600 font-semibold bg-indigo-100 text-indigo-700 px-4 py-1 rounded-full">
              Welcome, {user?.name}
            </span>
          </div>
          <div className="flex items-center space-x-2">
            {['dashboard', 'transactions', 'budgets', 'investments', 'analytics'].map((v) => (
              <button
                key={v}
                onClick={() => setView(v)}
                className={`px-6 py-3 rounded-2xl font-semibold text-sm transition-all duration-300 ${
                  view === v 
                    ? 'bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg hover:shadow-xl transform -translate-y-0.5' 
                    : 'text-gray-600 hover:text-indigo-600 hover:bg-indigo-50 border border-gray-200 hover:border-indigo-300'
                }`}
              >
                {v.charAt(0).toUpperCase() + v.slice(1)}
              </button>
            ))}
            <button onClick={logout} className="bg-gradient-to-r from-red-500 to-rose-600 text-white px-8 py-3 rounded-2xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300">
              Logout
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-12">
        <div className="mb-12 flex justify-between items-center">
          <h2 className="text-4xl font-black text-gray-900 capitalize">{view}</h2>
          <button onClick={refreshAll} className="bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white px-8 py-4 rounded-2xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300">
            Refresh Data
          </button>
        </div>

        {view === 'dashboard' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <AnalyticsDashboard />
          </div>
        )}

        {view === 'transactions' && (
          <div>
            <div className="bg-white rounded-3xl shadow-2xl p-8 mb-8">
              <h3 className="text-2xl font-bold text-gray-900 mb-6">Add Transaction</h3>
              <form onSubmit={addTransaction} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input name="amount" type="number" step="0.01" placeholder="Amount" className="p-4 border rounded-xl focus:ring-2 focus:ring-blue-500" required />
                <select name="type" className="p-4 border rounded-xl focus:ring-2 focus:ring-blue-500" required>
                  <option value="">Type</option>
                  <option value="income">Income</option>
                  <option value="expense">Expense</option>
                </select>
                <select name="category" className="p-4 border rounded-xl focus:ring-2 focus:ring-blue-500" required>
                  <option value="">Category</option>
                  <option value="salary">Salary</option>
                  <option value="freelance">Freelance</option>
                  <option value="grocery">Grocery</option>
                  <option value="rent">Rent</option>
                  <option value="utilities">Utilities</option>
                  <option value="transport">Transport</option>
                  <option value="entertainment">Entertainment</option>
                  <option value="other">Other</option>
                </select>
                <input name="date" type="date" className="p-4 border rounded-xl focus:ring-2 focus:ring-blue-500" required />
                <button type="submit" className="md:col-span-2 bg-blue-600 text-white p-4 rounded-xl font-bold hover:bg-blue-700">Add Transaction</button>
              </form>
            </div>
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden">
              <TransactionList transactions={transactions} />
            </div>
          </div>
        )}

        {/* Other views similar */}
      </main>
    </div>
  );
}

export default App;
